+        } else if !shouldMonitor, monitoring {
+            monitoring = false
+            PermissionMonitor.shared.unregister()
+        }
+    }
+
+    static func stopMonitoring(_ monitoring: inout Bool) {
+        guard monitoring else { return }
+        monitoring = false
+        PermissionMonitor.shared.unregister()
+    }
+}

